VALUES (
  'e5842c6b-a74d-4f5a-9ff0-1e93bb32032b',
  'approved'::application_status,
  $seed${"title":"NTA Antrag Anna Müller","summary":"In Review","finalSubmitted":true,"submittedAt":"2026-03-12T08:15:00.000Z","personalData":{"vorname":"Anna","name":"Müller","email":"anna.mueller@students.uzh.ch","phone":"+41 79 123 45 01","matrikel":"21-845-901","studiengang":"BSc Psychologie","semester":"4","antragsart":"studium"},"attestFiles":[{"id":"seed-attest-anna","name":"Fachärztliches_Attest_Anna_Müller.md","size":2100,"type":"text/markdown","url":"/attest/seed/fachaerztliches-attest-anna-mueller.md"}],"consultation":{"status":"done","date":"Montag, 10. März 2026","slot":"10:00–10:45","location":"NTA-Fachstelle, Rämistrasse 74, 8001 Zürich (Raum 2.14)","advisor":"Dr. Sandra Meier, NTA-Fachstelle UZH"},"recommendation":{"ready":true,"releasedHtml":"<p>Sehr geehrte Damen und Herren,</p><p>im Rahmen der Beratung am 10.03.2026 habe ich mit Frau <strong>Anna Müller</strong> den Nachteilsausgleich für das Frühlingssemester 2026 besprochen. Das fachärztliche Attest bestätigt eine ADHS (kombinierte Form) mit studienrelevanter Beeinträchtigung bei langen Veranstaltungen und unangekündigter mündlicher Beteiligung.</p><p><strong>Empfehlung der Fachstelle:</strong></p><ul><li>Einmaliger Ausgleich für ein Semester mit Fokus auf Lehrveranstaltungen und Prüfungen.</li><li>Zusätzliche Pausen sowie Verzicht auf unaufgefordertes mündliches Aufbieten.</li><li>Angepasste Prüfungsunterlagen und verlängerte Bearbeitungszeit bei schriftlichen Prüfungen.</li></ul><p>Die beantragten Massnahmen stehen in einem angemessenen Verhältnis zur dokumentierten Einschränkung und ermöglichen eine gleichwertige Teilhabe.</p><p>Freundliche Grüsse<br/>Dr. Sandra Meier, NTA-Fachstelle UZH</p>","releasedText":"Sehr geehrte Damen und Herren, im Rahmen der Beratung am 10.03.2026 habe ich mit Frau Anna Müller den Nachteilsausgleich für das Frühlingssemester 2026 besprochen. Das fachärztliche Attest bestätigt eine ADHS (kombinierte Form) mit studienrelevanter Beeinträchtigung bei langen Veranstaltungen und unangekündigter mündlicher Beteiligung. Empfehlung der Fachstelle: Einmaliger Ausgleich für ein Semester mit Fokus auf Lehrveranstaltungen und Prüfungen. Zusätzliche Pausen sowie Verzicht auf unaufgefordertes mündliches Aufbieten. Angepasste Prüfungsunterlagen und verlängerte Bearbeitungszeit bei schriftlichen Prüfungen. Die beantragten Massnahmen stehen in einem angemessenen Verhältnis zur dokumentierten Einschränkung und ermöglichen eine gleichwertige Teilhabe. Freundliche Grüsse Dr. Sandra Meier, NTA-Fachstelle UZH","releasedAt":"2026-03-18T14:30:00.000Z","releasedBy":"Dr. Sandra Meier, NTA-Fachstelle UZH","workspaceReview":{"postSubmit":{"forwardedAt":"2026-03-22T09:00:00.000Z","blocks":{"applicant":{"phase":"confirmed"},"attest":{"phase":"confirmed"},"definition":{"phase":"confirmed"},"duration":{"phase":"confirmed"},"scope":{"phase":"confirmed"},"lectureMeasures":{"phase":"confirmed"},"assessmentMeasures":{"phase":"confirmed"}}}}},"applicationDefinition":{"situationDescription":"Seit dem Wechsel ins Hauptstudium zeigt sich bei mir eine deutliche Verschlechterung der Konzentration in langen Vorlesungen. Die ADHS-Diagnose ist seit der Oberstufe dokumentiert; im aktuellen Semester führe ich mehrere Blockveranstaltungen mit mündlicher Beteiligung durch. Ohne strukturierte Pausen und ohne unangekündigte mündliche Abfragen gerate ich in Prüfungssituationen unter Stress, obwohl ich mich fachlich gut vorbereite.","duration":"one_semester","scopeSelections":["Schriftliche Prüfungen","Mündliche Prüfungen","Während Lehrveranstaltungen"],"lectureMeasures":["m1","m6"],"assessmentMeasures":["m2","m4"]},"r4DecisionReview":{"blocks":{"duration":{"confirmed":true,"rows":[{"key":"full_study","title":"Gesamte Studiendauer","description":"Der Ausgleich gilt für die gesamte Dauer des Studiums.","studentSelected":false,"r4Approved":false},{"key":"one_semester","title":"Einmalig für ein Semester","description":"Der Ausgleich gilt für ein Semester.","studentSelected":true,"r4Approved":true}]},"scope":{"confirmed":true,"rows":[{"key":"Schriftliche Prüfungen","title":"Schriftliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Mündliche Prüfungen","title":"Mündliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Schriftliche Arbeiten","title":"Schriftliche Arbeiten","studentSelected":false,"r4Approved":false},{"key":"Während Lehrveranstaltungen","title":"Während Lehrveranstaltungen","studentSelected":true,"r4Approved":true},{"key":"Praktika","title":"Praktika","studentSelected":false,"r4Approved":false}]},"lectureMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Zusätzliche Pausen","description":"Möglichkeit, während Lehrveranstaltungen zusätzliche Pausen einzulegen.","studentSelected":true,"r4Approved":true},{"key":"m2","title":"Einzelarbeit statt Gruppenarbeit","description":"Gruppenarbeiten können durch gleichwertige Einzelarbeiten ersetzt werden.","studentSelected":false,"r4Approved":false},{"key":"m3","title":"Angepasste Präsenzpflicht","description":"Die Präsenzpflicht wird individuell angepasst.","studentSelected":false,"r4Approved":false},{"key":"m4","title":"Audioaufnahme-Erlaubnis","description":"Lehrveranstaltungen dürfen zu persönlichen Lernzwecken aufgezeichnet werden.","studentSelected":false,"r4Approved":false},{"key":"m5","title":"Reservierter Sitzplatz","description":"Ein fester Sitzplatz wird reserviert.","studentSelected":false,"r4Approved":false},{"key":"m6","title":"Kein unaufgefordertes Aufrufen","description":"Die Lehrperson verzichtet auf unaufgefordertes mündliches Aufbieten.","studentSelected":true,"r4Approved":true}]},"assessmentMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Einsatz technischer Hilfsmittel","description":"Nutzung von Hilfsmitteln wie Notebook oder Screenreader.","studentSelected":false,"r4Approved":false},{"key":"m2","title":"Anpassung der Prüfungsunterlagen","description":"Prüfungsunterlagen in angepasster Form.","studentSelected":true,"r4Approved":true},{"key":"m3","title":"Einsatz personeller Unterstützung","description":"Begleitung durch Assistenzperson während der Prüfung.","studentSelected":false,"r4Approved":false},{"key":"m4","title":"Verlängerung der Prüfungszeit","description":"Zusätzliche Bearbeitungszeit bei Prüfungen.","studentSelected":true,"r4Approved":true},{"key":"m5","title":"Separate Prüfungsräume","description":"Prüfung in ruhigerem Einzelraum.","studentSelected":false,"r4Approved":false},{"key":"m6","title":"Mündliche statt schriftliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false},{"key":"m7","title":"Schriftliche statt mündliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false}]}},"updatedAt":"2026-04-10T12:00:00.000Z"},"r1PortalFlowStep":"step6_submitted"}$seed$::jsonb,
