INSERT INTO public.applications (applicant_id, status, data, current_phase)
VALUES (
  'e5842c6b-a74d-4f5a-9ff0-1e93bb32032b',
  'approved'::application_status,
  $seed${"title":"NTA Antrag Luca Ferreira","summary":"In Review","finalSubmitted":true,"submittedAt":"2026-03-05T11:20:00.000Z","personalData":{"vorname":"Luca","name":"Ferreira","email":"luca.ferreira@students.uzh.ch","phone":"+41 78 234 56 02","matrikel":"19-712-334","studiengang":"BSc Informatik","semester":"6","antragsart":"studium"},"attestFiles":[{"id":"seed-attest-luca","name":"Fachärztliches_Attest_Luca_Ferreira.md","size":1950,"type":"text/markdown","url":"/attest/seed/fachaerztliches-attest-luca-ferreira.md"}],"consultation":{"status":"done","date":"Donnerstag, 6. März 2026","slot":"14:15–15:00","location":"NTA-Fachstelle, Rämistrasse 74, 8001 Zürich (Raum 2.14)","advisor":"Dr. Sandra Meier, NTA-Fachstelle UZH"},"recommendation":{"ready":true,"releasedHtml":"<p>Sehr geehrte Damen und Herren,</p><p>Herr <strong>Luca Ferreira</strong> hat am 06.03.2026 eine Beratung wahrgenommen. Das neurologische Attest beschreibt chronische Migräne mit studienrelevanter Belastung durch Lichtreize und längere Bildschirmarbeit.</p><p><strong>Empfehlung:</strong></p><ul><li>Audioaufnahmen zu persönlichen Lernzwecken in Lehrveranstaltungen.</li><li>Angepasste Prüfungsunterlagen und verlängerte Prüfungszeit.</li><li>Individuell angepasste Präsenzregelung sowie ruhiger Prüfungsraum, soweit möglich.</li></ul><p>Die Kombination der Massnahmen ist für ein Semester angemessen und unterstützt die fachliche Leistungsfähigkeit ohne Benachteiligung.</p><p>Freundliche Grüsse<br/>Dr. Sandra Meier, NTA-Fachstelle UZH</p>","releasedText":"Sehr geehrte Damen und Herren, Herr Luca Ferreira hat am 06.03.2026 eine Beratung wahrgenommen. Das neurologische Attest beschreibt chronische Migräne mit studienrelevanter Belastung durch Lichtreize und längere Bildschirmarbeit. Empfehlung: Audioaufnahmen zu persönlichen Lernzwecken in Lehrveranstaltungen. Angepasste Prüfungsunterlagen und verlängerte Prüfungszeit. Individuell angepasste Präsenzregelung sowie ruhiger Prüfungsraum, soweit möglich. Die Kombination der Massnahmen ist für ein Semester angemessen und unterstützt die fachliche Leistungsfähigkeit ohne Benachteiligung. Freundliche Grüsse Dr. Sandra Meier, NTA-Fachstelle UZH","releasedAt":"2026-03-14T16:00:00.000Z","releasedBy":"Dr. Sandra Meier, NTA-Fachstelle UZH","workspaceReview":{"postSubmit":{"forwardedAt":"2026-03-19T10:30:00.000Z","blocks":{"applicant":{"phase":"confirmed"},"attest":{"phase":"confirmed"},"definition":{"phase":"confirmed"},"duration":{"phase":"confirmed"},"scope":{"phase":"confirmed"},"lectureMeasures":{"phase":"confirmed"},"assessmentMeasures":{"phase":"confirmed"}}}}},"applicationDefinition":{"situationDescription":"Aufgrund chronischer Migräne mit Photosensibilität kann ich nicht zuverlässig an allen Präsenzveranstaltungen teilnehmen. Während Attacken bin ich nicht prüfungsfähig. Für das Repetitionssemester in Analysis und Programmierung benötige ich planbare Anpassungen, damit ich Lernstoff nacharbeiten und Prüfungen ohne zusätzliche gesundheitliche Belastung absolvieren kann.","duration":"one_semester","scopeSelections":["Schriftliche Prüfungen","Schriftliche Arbeiten","Während Lehrveranstaltungen"],"lectureMeasures":["m3","m4"],"assessmentMeasures":["m2","m4","m5"]},"r4DecisionReview":{"blocks":{"duration":{"confirmed":true,"rows":[{"key":"full_study","title":"Gesamte Studiendauer","description":"Der Ausgleich gilt für die gesamte Dauer des Studiums.","studentSelected":false,"r4Approved":false},{"key":"one_semester","title":"Einmalig für ein Semester","description":"Der Ausgleich gilt für ein Semester.","studentSelected":true,"r4Approved":true}]},"scope":{"confirmed":true,"rows":[{"key":"Schriftliche Prüfungen","title":"Schriftliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Mündliche Prüfungen","title":"Mündliche Prüfungen","studentSelected":false,"r4Approved":false},{"key":"Schriftliche Arbeiten","title":"Schriftliche Arbeiten","studentSelected":true,"r4Approved":true},{"key":"Während Lehrveranstaltungen","title":"Während Lehrveranstaltungen","studentSelected":true,"r4Approved":true},{"key":"Praktika","title":"Praktika","studentSelected":false,"r4Approved":false}]},"lectureMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Zusätzliche Pausen","description":"Möglichkeit, während Lehrveranstaltungen zusätzliche Pausen einzulegen.","studentSelected":false,"r4Approved":false},{"key":"m2","title":"Einzelarbeit statt Gruppenarbeit","description":"Gruppenarbeiten können durch gleichwertige Einzelarbeiten ersetzt werden.","studentSelected":false,"r4Approved":false},{"key":"m3","title":"Angepasste Präsenzpflicht","description":"Die Präsenzpflicht wird individuell angepasst.","studentSelected":true,"r4Approved":true},{"key":"m4","title":"Audioaufnahme-Erlaubnis","description":"Lehrveranstaltungen dürfen zu persönlichen Lernzwecken aufgezeichnet werden.","studentSelected":true,"r4Approved":true},{"key":"m5","title":"Reservierter Sitzplatz","description":"Ein fester Sitzplatz wird reserviert.","studentSelected":false,"r4Approved":false},{"key":"m6","title":"Kein unaufgefordertes Aufrufen","description":"Die Lehrperson verzichtet auf unaufgefordertes mündliches Aufbieten.","studentSelected":false,"r4Approved":false}]},"assessmentMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Einsatz technischer Hilfsmittel","description":"Nutzung von Hilfsmitteln wie Notebook oder Screenreader.","studentSelected":false,"r4Approved":false},{"key":"m2","title":"Anpassung der Prüfungsunterlagen","description":"Prüfungsunterlagen in angepasster Form.","studentSelected":true,"r4Approved":true},{"key":"m3","title":"Einsatz personeller Unterstützung","description":"Begleitung durch Assistenzperson während der Prüfung.","studentSelected":false,"r4Approved":false},{"key":"m4","title":"Verlängerung der Prüfungszeit","description":"Zusätzliche Bearbeitungszeit bei Prüfungen.","studentSelected":true,"r4Approved":true},{"key":"m5","title":"Separate Prüfungsräume","description":"Prüfung in ruhigerem Einzelraum.","studentSelected":true,"r4Approved":true},{"key":"m6","title":"Mündliche statt schriftliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false},{"key":"m7","title":"Schriftliche statt mündliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false}]}},"updatedAt":"2026-04-10T12:00:00.000Z"},"r1PortalFlowStep":"step6_submitted"}$seed$::jsonb,
