  'approved'::application_status,
  $seed${"title":"NTA Antrag Sofia Nakamura","summary":"In Review","finalSubmitted":true,"submittedAt":"2026-02-20T09:40:00.000Z","personalData":{"vorname":"Sofia","name":"Nakamura","email":"sofia.nakamura@students.uzh.ch","phone":"+41 76 345 67 03","matrikel":"18-556-778","studiengang":"BSc Biologie","semester":"8","antragsart":"studium"},"attestFiles":[{"id":"seed-attest-sofia","name":"Fachärztliches_Attest_Sofia_Nakamura.md","size":2050,"type":"text/markdown","url":"/attest/seed/fachaerztliches-attest-sofia-nakamura.md"}],"consultation":{"status":"done","date":"Dienstag, 18. Februar 2026","slot":"09:30–10:15","location":"NTA-Fachstelle, Rämistrasse 74, 8001 Zürich (Raum 2.14)","advisor":"Dr. Sandra Meier, NTA-Fachstelle UZH"},"recommendation":{"ready":true,"releasedHtml":"<p>Sehr geehrte Damen und Herren,</p><p>Frau <strong>Sofia Nakamura</strong> ist seit mehreren Semestern in der Betreuung der NTA-Fachstelle bekannt. Das endokrinologische Attest bestätigt Diabetes Typ 1 mit Notwendigkeit strukturierter Pausen und Notfallzugang.</p><p><strong>Empfehlung für die gesamte Studiendauer:</strong></p><ul><li>Reservierter Sitzplatz nahe Ausgang in Lehrveranstaltungen.</li><li>Zusätzliche Pausen in Prüfungen.</li><li>Technische Hilfsmittel und verlängerte Bearbeitungszeit bei schriftlichen Leistungsnachweisen.</li></ul><p>Die Massnahmen sind medizinisch begründet und im Labor- und Praktikumsbetrieb bereits erprobt.</p><p>Freundliche Grüsse<br/>Dr. Sandra Meier, NTA-Fachstelle UZH</p>","releasedText":"Sehr geehrte Damen und Herren, Frau Sofia Nakamura ist seit mehreren Semestern in der Betreuung der NTA-Fachstelle bekannt. Das endokrinologische Attest bestätigt Diabetes Typ 1 mit Notwendigkeit strukturierter Pausen und Notfallzugang. Empfehlung für die gesamte Studiendauer: Reservierter Sitzplatz nahe Ausgang in Lehrveranstaltungen. Zusätzliche Pausen in Prüfungen. Technische Hilfsmittel und verlängerte Bearbeitungszeit bei schriftlichen Leistungsnachweisen. Die Massnahmen sind medizinisch begründet und im Labor- und Praktikumsbetrieb bereits erprobt. Freundliche Grüsse Dr. Sandra Meier, NTA-Fachstelle UZH","releasedAt":"2026-02-28T11:15:00.000Z","releasedBy":"Dr. Sandra Meier, NTA-Fachstelle UZH","workspaceReview":{"postSubmit":{"forwardedAt":"2026-03-05T08:45:00.000Z","blocks":{"applicant":{"phase":"confirmed"},"attest":{"phase":"confirmed"},"definition":{"phase":"confirmed"},"duration":{"phase":"confirmed"},"scope":{"phase":"confirmed"},"lectureMeasures":{"phase":"confirmed"},"assessmentMeasures":{"phase":"confirmed"}}}}},"applicationDefinition":{"situationDescription":"Mit Diabetes Typ 1 muss ich während längerer Vorlesungen und Prüfungen regelmässig Essen zu mir nehmen und meinen Blutzucker kontrollieren. In grossen Hörsälen ist ein sicherer Zugang zum Ausgang wichtig. Ich beantrage deshalb dauerhafte Massnahmen für die gesamte Studiendauer.","duration":"full_study","scopeSelections":["Schriftliche Prüfungen","Mündliche Prüfungen","Während Lehrveranstaltungen","Praktika"],"lectureMeasures":["m1","m5"],"assessmentMeasures":["m1","m4"]},"r4DecisionReview":{"blocks":{"duration":{"confirmed":true,"rows":[{"key":"full_study","title":"Gesamte Studiendauer","description":"Der Ausgleich gilt für die gesamte Dauer des Studiums.","studentSelected":true,"r4Approved":true},{"key":"one_semester","title":"Einmalig für ein Semester","description":"Der Ausgleich gilt für ein Semester.","studentSelected":false,"r4Approved":false}]},"scope":{"confirmed":true,"rows":[{"key":"Schriftliche Prüfungen","title":"Schriftliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Mündliche Prüfungen","title":"Mündliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Schriftliche Arbeiten","title":"Schriftliche Arbeiten","studentSelected":false,"r4Approved":false},{"key":"Während Lehrveranstaltungen","title":"Während Lehrveranstaltungen","studentSelected":true,"r4Approved":true},{"key":"Praktika","title":"Praktika","studentSelected":true,"r4Approved":true}]},"lectureMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Zusätzliche Pausen","description":"Möglichkeit, während Lehrveranstaltungen zusätzliche Pausen einzulegen.","studentSelected":true,"r4Approved":true},{"key":"m2","title":"Einzelarbeit statt Gruppenarbeit","description":"Gruppenarbeiten können durch gleichwertige Einzelarbeiten ersetzt werden.","studentSelected":false,"r4Approved":false},{"key":"m3","title":"Angepasste Präsenzpflicht","description":"Die Präsenzpflicht wird individuell angepasst.","studentSelected":false,"r4Approved":false},{"key":"m4","title":"Audioaufnahme-Erlaubnis","description":"Lehrveranstaltungen dürfen zu persönlichen Lernzwecken aufgezeichnet werden.","studentSelected":false,"r4Approved":false},{"key":"m5","title":"Reservierter Sitzplatz","description":"Ein fester Sitzplatz wird reserviert.","studentSelected":true,"r4Approved":true},{"key":"m6","title":"Kein unaufgefordertes Aufrufen","description":"Die Lehrperson verzichtet auf unaufgefordertes mündliches Aufbieten.","studentSelected":false,"r4Approved":false}]},"assessmentMeasures":{"confirmed":true,"rows":[{"key":"m1","title":"Einsatz technischer Hilfsmittel","description":"Nutzung von Hilfsmitteln wie Notebook oder Screenreader.","studentSelected":true,"r4Approved":true},{"key":"m2","title":"Anpassung der Prüfungsunterlagen","description":"Prüfungsunterlagen in angepasster Form.","studentSelected":false,"r4Approved":false},{"key":"m3","title":"Einsatz personeller Unterstützung","description":"Begleitung durch Assistenzperson während der Prüfung.","studentSelected":false,"r4Approved":false},{"key":"m4","title":"Verlängerung der Prüfungszeit","description":"Zusätzliche Bearbeitungszeit bei Prüfungen.","studentSelected":true,"r4Approved":true},{"key":"m5","title":"Separate Prüfungsräume","description":"Prüfung in ruhigerem Einzelraum.","studentSelected":false,"r4Approved":false},{"key":"m6","title":"Mündliche statt schriftliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false},{"key":"m7","title":"Schriftliche statt mündliche Prüfungen","description":"Alternative Prüfungsformen.","studentSelected":false,"r4Approved":false}]}},"updatedAt":"2026-04-10T12:00:00.000Z"},"r1PortalFlowStep":"step6_submitted"}$seed$::jsonb,
