INSERT INTO public.applications (applicant_id, status, data, current_phase)
VALUES (
  'e5842c6b-a74d-4f5a-9ff0-1e93bb32032b',
  'approved'::application_status,
  $seed${"title":"NTA Antrag Jonas Keller","summary":"In Review","finalSubmitted":true,"submittedAt":"2026-03-01T13:05:00.000Z","personalData":{"vorname":"Jonas","name":"Keller","email":"jonas.keller@students.uzh.ch","phone":"+41 79 456 78 04","matrikel":"22-901-445","studiengang":"BA Wirtschaftswissenschaften","semester":"3","antragsart":"studium"},"attestFiles":[{"id":"seed-attest-jonas","name":"Fachärztliches_Attest_Jonas_Keller.md","size":1880,"type":"text/markdown","url":"/attest/seed/fachaerztliches-attest-jonas-keller.md"}],"consultation":{"status":"done","date":"Freitag, 28. Februar 2026","slot":"11:30–12:15","location":"NTA-Fachstelle, Rämistrasse 74, 8001 Zürich (Raum 2.14)","advisor":"Dr. Sandra Meier, NTA-Fachstelle UZH"},"recommendation":{"ready":true,"releasedHtml":"<p>Sehr geehrte Damen und Herren,</p><p>Herr <strong>Jonas Keller</strong> hat am 28.02.2026 die Beratung besucht. Das attest der Handchirurgie beschreibt eine temporäre Einschränkung der Feinmotorik nach operativem Eingriff.</p><p><strong>Empfehlung (ein Semester):</strong></p><ul><li>Einsatz technischer Hilfsmittel bei Leistungsnachweisen.</li><li>Verlängerung der Prüfungszeit.</li><li>Ersetzung von Gruppenarbeiten durch gleichwertige Einzelarbeiten, wo fachlich vertretbar.</li></ul><p>Die Beantragung ist auf den dokumentierten Heilungsverlauf ausgerichtet; eine erneute ärztliche Bestätigung kann nach Ablauf des Semesters verlangt werden.</p><p>Freundliche Grüsse<br/>Dr. Sandra Meier, NTA-Fachstelle UZH</p>","releasedText":"Sehr geehrte Damen und Herren, Herr Jonas Keller hat am 28.02.2026 die Beratung besucht. Das attest der Handchirurgie beschreibt eine temporäre Einschränkung der Feinmotorik nach operativem Eingriff. Empfehlung (ein Semester): Einsatz technischer Hilfsmittel bei Leistungsnachweisen. Verlängerung der Prüfungszeit. Ersetzung von Gruppenarbeiten durch gleichwertige Einzelarbeiten, wo fachlich vertretbar. Die Beantragung ist auf den dokumentierten Heilungsverlauf ausgerich