ismässig und entsprechen bewährten Standards der NTA-Fachstelle. Freundliche Grüsse Dr. Sandra Meier, NTA-Fachstelle UZH","releasedAt":"2026-03-25T13:20:00.000Z","releasedBy":"Dr. Sandra Meier, NTA-Fachstelle UZH","workspaceReview":{"postSubmit":{"forwardedAt":"2026-04-02T09:15:00.000Z","blocks":{"applicant":{"phase":"confirmed"},"attest":{"phase":"confirmed"},"definition":{"phase":"confirmed"},"duration":{"phase":"confirmed"},"scope":{"phase":"confirmed"},"lectureMeasures":{"phase":"confirmed"},"assessmentMeasures":{"phase":"confirmed"}}}}},"applicationDefinition":{"situationDescription":"In grossen Veranstaltungen und spontanen Diskussionen erlebe ich starke Überforderung. Eine Autismus-Diagnose erklärt meinen Bedarf an planbaren Abläufen und schriftlicher Kommunikation. Ich möchte für die gesamte Studiendauer NTA-Massnahmen, damit ich Leistung zeigen kann, ohne ständig mündlich exponiert zu werden.","duration":"full_study","scopeSelections":["Schriftliche Prüfungen","Mündliche Prüfungen","Während Lehrveranstaltungen"],"lectureMeasures":["m3","m6"],"assessmentMeasures":["m6","m7"]},"r4DecisionReview":{"blocks":{"duration":{"confirmed":true,"rows":[{"key":"full_study","title":"Gesamte Studiendauer","description":"Der Ausgleich gilt für die gesamte Dauer des Studiums.","studentSelected":true,"r4Approved":true},{"key":"one_semester","title":"Einmalig für ein Semester","description":"Der Ausgleich gilt für ein Semester.","studentSelected":false,"r4Approved":false}]},"scope":{"confirmed":true,"rows":[{"key":"Schriftliche Prüfungen","title":"Schriftliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Mündliche Prüfungen","title":"Mündliche Prüfungen","studentSelected":true,"r4Approved":true},{"key":"Schriftliche Arbeiten","title":"Schriftliche Arbeiten","studentSelected":false,"r4Approved":false},{"key":"Während Lehrveranstaltungen","title":"Während Lehrveranstaltungen","studentSelected":true,"r4Approved":true},{"key":"Praktika","title":"Praktika","student